import React, { FC, useState, useEffect } from "react";
import { colors, spacing, typography, radius } from "@tokens";
import { useTheme } from "@ui/context/ThemeProvider";
import { Icon } from "../../atoms/Icon/Icon";
import { Text as AppText } from "../../atoms/Text/Text";

interface SidebarItemProps {
    label: string;
    icon: string;
    active?: boolean;
    disabled?: boolean;
    expandable?: boolean;
    isExpanded?: boolean;
    isHovered?: boolean;
    isSectionActive?: boolean;
    onClick?: () => void;
    onHover: (hovered: boolean) => void;
}

export const SidebarItem: FC<SidebarItemProps> = ({
    label,
    icon,
    active,
    disabled,
    expandable,
    isExpanded,
    isHovered,
    isSectionActive = false,
    onClick,
    onHover,
}) => {
    const { theme } = useTheme();
    const { semantic } = colors[theme];
    const [mounted, setMounted] = useState(false);

    useEffect(() => {
        const timer = setTimeout(() => setMounted(true), 0);
        return () => clearTimeout(timer);
    }, []);

    // Lógica interna: sin cambios (DARK depende de esto)
    const showSelected = active || isSectionActive;
    const showHover = (isHovered || isExpanded) && !disabled;
    const isGroup = Boolean(expandable);

    // LIGHT only: padres con children NO se pintan como selected (evitar doble activo)
    const showSelectedVisual = theme === "light" ? (showSelected && !isGroup) : showSelected;
    // LIGHT: grupo en sección activa = normal/muted, no hover (solo hover al pasar mouse)
    const showHoverVisual = theme === "light" && isGroup && showSelected ? false : showHover;

    const getVisualStyle = (): React.CSSProperties => {
        if (theme === "light") {
            return {
                display: "flex",
                alignItems: "center",
                justifyContent: "space-between",
                height: 40,
                padding: `0 ${spacing[12]}px`,
                borderRadius: radius["md"],
                backgroundColor: showSelectedVisual
                    ? "var(--semantic-nav-active-bg)"
                    : showHoverVisual
                        ? "var(--semantic-nav-hover-bg)"
                        : "transparent",
                color: showSelectedVisual
                    ? "var(--semantic-nav-active-fg)"
                    : showHoverVisual
                        ? "var(--semantic-sidebar-item-hover)"
                        : "var(--semantic-sidebar-item-default)",
                opacity: disabled ? 0.5 : 1,
                transition: "background-color 0.2s ease, color 0.2s ease",
            };
        }
        return {
            display: "flex",
            alignItems: "center",
            justifyContent: "space-between",
            height: 40,
            padding: `0 ${spacing[12]}px`,
            borderRadius: radius["md"],
            backgroundColor: showSelected
                ? semantic.surface.selected
                : showHover
                    ? semantic.surface.hover
                    : "transparent",
            color: showSelected
                ? semantic.primary.default
                : showHover
                    ? semantic.text.hover
                    : semantic.text.default,
            opacity: disabled ? 0.5 : 1,
            transition: "background-color 0.2s ease, color 0.2s ease",
        };
    };

    const iconColor = theme === "light"
        ? (showSelectedVisual ? "var(--semantic-nav-active-fg)" : showHoverVisual ? "var(--semantic-sidebar-item-hover)" : "var(--semantic-sidebar-item-default)")
        : (showSelected ? semantic.primary.default : showHover ? semantic.text.hover : semantic.text.default);

    const wrapperStyle: React.CSSProperties = {
        paddingBottom: spacing[4],
        cursor: disabled ? "not-allowed" : "pointer",
        width: "100%",
    };

    const safeStyle = mounted ? getVisualStyle() : undefined;

    return (
        <div
            style={wrapperStyle}
            role="button"
            aria-disabled={disabled}
            onClick={() => !disabled && onClick?.()}
            onMouseEnter={() => onHover(true)}
            onMouseLeave={() => onHover(false)}
        >
            <div style={safeStyle}>
                <div style={{ display: "flex", alignItems: "center", gap: spacing[12] }}>
                    <Icon size={16} title={icon} name={icon} color={iconColor} />
                    <AppText
                        style={{
                            fontSize: typography.fontSize.sm,
                            fontWeight: showSelectedVisual ? typography.fontWeight.medium : typography.fontWeight.regular,
                            color: "inherit",
                        }}
                    >
                        {label}
                    </AppText>
                </div>

                {expandable && (
                    <div
                        style={{
                            transition: "transform 0.2s ease",
                            transform: mounted && isExpanded ? "rotate(180deg)" : "rotate(0deg)",
                            display: "flex",
                        }}
                    >
                        <Icon size={18} title="Expandir" name="chevron-down" color={iconColor} />
                    </div>
                )}
            </div>
        </div>
    );
};
